+    if cfg!(target_os = "linux") {
+        cmd.arg(format!("-Wl,-rpath,{}", target.display()));
+    } else if cfg!(target_os = "macos") {
+        cmd.arg("-Wl,-rpath,@loader_path")
+            .arg(format!("-Wl,-rpath,{}", target.display()));
