+#ifndef SAIKURO_CPP_SAIKURO_HPP
+#define SAIKURO_CPP_SAIKURO_HPP
+
+#include <stdexcept>
+#include <string>
+#include <memory>
+#include <utility>
+
+extern "C" {
+#include "saikuro.h"
+}
+
+namespace saikuro {
+
+class Error : public std::runtime_error {
+public:
+    explicit Error(const std::string& message) : std::runtime_error(message) {}
+};
+
+inline std::string take_owned_c_string(char* ptr) {
+    if (ptr == nullptr) {
+        return {};
+    }
+    std::unique_ptr<char, decltype(&saikuro_string_free)> guard(ptr, &saikuro_string_free);
+    std::string out(guard.get());
+    return out;
+}
+
+inline std::string last_error() {
+    return take_owned_c_string(saikuro_last_error_message());
+}
+
+class Client {
+public:
+    class Stream {
+    public:
+        explicit Stream(saikuro_stream_t handle) : handle_(handle) {
+            if (handle_ == nullptr) {
+                throw Error(last_error());
+            }
+        }
+
+        Stream(const Stream&) = delete;
+        Stream& operator=(const Stream&) = delete;
+
+        Stream(Stream&& other) noexcept : handle_(other.handle_) {
+            other.handle_ = nullptr;
+        }
+
+        Stream& operator=(Stream&& other) noexcept {
+            if (this != &other) {
+                destroy();
+                handle_ = other.handle_;
+                other.handle_ = nullptr;
+            }
+            return *this;
+        }
+
+        ~Stream() {
+            destroy();
+        }
+
+        bool next_json(std::string& out_item_json) {
+            char* raw = nullptr;
+            int done = 0;
+            if (saikuro_stream_next_json(handle_, &raw, &done) != 0) {
+                throw Error(last_error());
+            }
+            if (done != 0) {
+                out_item_json.clear();
+                return false;
+            }
+            out_item_json = take_owned_c_string(raw);
+            return true;
+        }
+
+    private:
+        void destroy() {
+            if (handle_ != nullptr) {
+                saikuro_stream_free(handle_);
+                handle_ = nullptr;
+            }
+        }
+
+        saikuro_stream_t handle_ = nullptr;
+    };
+
+    class Channel {
+    public:
+        explicit Channel(saikuro_channel_t handle) : handle_(handle) {
+            if (handle_ == nullptr) {
+                throw Error(last_error());
+            }
+        }
+
+        Channel(const Channel&) = delete;
+        Channel& operator=(const Channel&) = delete;
+
+        Channel(Channel&& other) noexcept : handle_(other.handle_), open_(other.open_) {
+            other.handle_ = nullptr;
+            other.open_ = false;
+        }
+
