+std::vector<std::string> split_args_aware_of_nesting(const std::string& text) {
+    std::vector<std::string> out;
+    if (trim(text).empty()) {
+        return out;
+    }
+
+    std::string current;
+    int paren_depth = 0;
+    int bracket_depth = 0;
+    int angle_depth = 0;
+    bool in_single_quote = false;
+    bool in_double_quote = false;
+    bool escaped = false;
+
+    for (size_t i = 0; i < text.size(); ++i) {
+        const char c = text[i];
+
+        if (in_double_quote) {
+            current += c;
+            if (escaped) {
+                escaped = false;
+            } else if (c == '\\') {
+                escaped = true;
+            } else if (c == '"') {
+                in_double_quote = false;
+            }
+            continue;
+        }
+
+        if (in_single_quote) {
+            current += c;
+            if (escaped) {
+                escaped = false;
+            } else if (c == '\\') {
+                escaped = true;
+            } else if (c == '\'') {
+                in_single_quote = false;
+            }
+            continue;
+        }
+
+        if (c == '"') {
+            in_double_quote = true;
+            current += c;
+            continue;
+        }
+        if (c == '\'') {
+            in_single_quote = true;
+            current += c;
+            continue;
+        }
+
+        if (c == '(') {
+            ++paren_depth;
+        } else if (c == ')' && paren_depth > 0) {
+            --paren_depth;
+        } else if (c == '[') {
+            ++bracket_depth;
+        } else if (c == ']' && bracket_depth > 0) {
+            --bracket_depth;
+        } else if (c == '<') {
+            ++angle_depth;
+        } else if (c == '>' && angle_depth > 0) {
+            --angle_depth;
+        }
+
+        if (c == ',' && paren_depth == 0 && bracket_depth == 0 && angle_depth == 0) {
+            out.push_back(current);
+            current.clear();
+            continue;
+        }
