+std::string remove_comments(const std::string& source) {
+    std::string out;
+    out.reserve(source.size());
+
+    bool in_line_comment = false;
+    bool in_block_comment = false;
+    bool in_double_quote = false;
+    bool in_single_quote = false;
+    bool in_raw_string = false;
+    bool escaped = false;
+    std::string raw_delim;
+
+    for (size_t i = 0; i < source.size(); ++i) {
+        const char c = source[i];
+        const char next = (i + 1 < source.size()) ? source[i + 1] : '\0';
+
+        if (in_line_comment) {
+            if (c == '\n' || c == '\r') {
+                in_line_comment = false;
+                out += c;
+            }
+            continue;
+        }
+
+        if (in_block_comment) {
+            if (c == '*' && next == '/') {
+                const char prev = out.empty() ? '\0' : out.back();
+                const char upcoming = next_non_space_char(source, i + 2);
+                if (is_ident_char(prev) && is_ident_char(upcoming)) {
+                    out += ' ';
+                }
+                in_block_comment = false;
+                ++i;
+                continue;
+            }
+            if (c == '\n' || c == '\r') {
+                out += c;
+            }
+            continue;
+        }
+
+        if (in_double_quote) {
+            out += c;
+            if (escaped) {
+                escaped = false;
+            } else if (c == '\\') {
+                escaped = true;
+            } else if (c == '"') {
+                in_double_quote = false;
+            }
+            continue;
+        }
+
+        if (in_single_quote) {
+            out += c;
+            if (escaped) {
+                escaped = false;
+            } else if (c == '\\') {
+                escaped = true;
+            } else if (c == '\'') {
+                in_single_quote = false;
+            }
+            continue;
+        }
+
+        if (in_raw_string) {
+            out += c;
+            const std::string terminator = ")" + raw_delim + "\"";
+            if (c == ')' && i + terminator.size() <= source.size()) {
+                if (source.substr(i, terminator.size()) == terminator) {
+                    for (size_t j = 1; j < terminator.size(); ++j) {
+                        out += source[i + j];
+                    }
+                    i += terminator.size() - 1;
+                    in_raw_string = false;
+                    raw_delim.clear();
+                }
+            }
+            continue;
+        }
+
+        if (c == '/' && next == '/') {
+            in_line_comment = true;
+            ++i;
+            continue;
+        }
+        if (c == '/' && next == '*') {
+            in_block_comment = true;
+            ++i;
+            continue;
+        }
+        if (c == '"') {
+            in_double_quote = true;
+            out += c;
+            continue;
+        }
+        if (c == 'R' && next == '"') {
+            size_t j = i + 2;
+            std::string delim;
+            while (j < source.size() && source[j] != '(') {
+                delim += source[j];
+                ++j;
+            }
+            if (j < source.size() && source[j] == '(') {
+                in_raw_string = true;
+                raw_delim = delim;
+                out.append(source, i, j - i + 1);
+                i = j;
+                continue;
+            }
+        }
+        if (c == '\'') {
+            in_single_quote = true;
+            out += c;
+            continue;
+        }
+
+        out += c;
+    }
+
+    return out;
+}
