+//! C binding generator.
+//!
+//! Produces:
+//! - A `saikuro_types.h` placeholder for named schema types.
+//! - One `<namespace>_client.h` per namespace with schema-aware C helper calls.
+//! - A `saikuro_generated.h` umbrella include.
+
+use saikuro_core::schema::{NamespaceSchema, Schema, Visibility};
+use std::collections::HashMap;
+
+use crate::{
+    error::{CodegenError, Result},
+    generator::{BindingGenerator, GeneratorOutput},
+};
+
+pub struct CGenerator;
+
+impl BindingGenerator for CGenerator {
+    fn generate(&self, schema: &Schema) -> Result<GeneratorOutput> {
+        let mut output = GeneratorOutput::default();
+
+        output.add("saikuro_types.h", self.generate_types(schema));
+
+        let mut includes = vec![
+            "#ifndef SAIKURO_GENERATED_H".to_owned(),
+            "#define SAIKURO_GENERATED_H".to_owned(),
+            String::new(),
+            "#include \"saikuro.h\"".to_owned(),
+            "#include \"saikuro_types.h\"".to_owned(),
+        ];
+
+        let mut ns_keys: Vec<_> = schema.namespaces.keys().collect();
+        ns_keys.sort();
+
+        let mut stem_to_names: HashMap<String, Vec<String>> = HashMap::new();
+        let mut folded_stem_to_names: HashMap<String, Vec<String>> = HashMap::new();
+        for ns_name in &ns_keys {
+            let stem = normalize_namespace_stem(ns_name);
+            stem_to_names
+                .entry(stem.clone())
+                .or_default()
+                .push((*ns_name).clone());
+            folded_stem_to_names
+                .entry(stem.to_ascii_uppercase())
+                .or_default()
+                .push((*ns_name).clone());
+        }
+        for (stem, names) in stem_to_names {
+            if names.len() > 1 {
+                return Err(CodegenError::Schema(format!(
+                    "namespace collision after normalization: stem '{stem}' produced by [{}]",
+                    names.join(", ")
+                )));
+            }
+        }
+        for (stem, names) in folded_stem_to_names {
+            if names.len() > 1 {
+                return Err(CodegenError::Schema(format!(
+                    "namespace collision after normalization: stem '{stem}' produced by [{}]",
+                    names.join(", ")
+                )));
+            }
+        }
+
+        for ns_name in ns_keys {
+            let ns_schema = &schema.namespaces[ns_name];
+            let safe = normalize_namespace_stem(ns_name);
+            let file_name = format!("{safe}_client.h");
+            let src = self.generate_namespace_client(ns_name, &safe, ns_schema)?;
+            output.add(&file_name, src);
+            includes.push(format!("#include \"{file_name}\""));
+        }
+
+        includes.push(String::new());
+        includes.push("#endif".to_owned());
+        includes.push(String::new());
+
+        output.add("saikuro_generated.h", includes.join("\n"));
+
+        Ok(output)
+    }
+}
+
+impl CGenerator {
+    fn generate_types(&self, _schema: &Schema) -> String {
+        [
+            "#ifndef SAIKURO_TYPES_H".to_owned(),
+            "#define SAIKURO_TYPES_H".to_owned(),
+            String::new(),
+            "/* AUTO-GENERATED by saikuro-codegen. DO NOT EDIT. */".to_owned(),
+            "/*".to_owned(),
+            " * Named schema types are currently represented as JSON strings in the C adapter."
+                .to_owned(),
+            " * This header is reserved for future generated struct/enum declarations.".to_owned(),
+            " */".to_owned(),
+            String::new(),
+            "#endif".to_owned(),
+            String::new(),
+        ]
+        .join("\n")
+    }
+
+    fn generate_namespace_client(
+        &self,
+        ns_name: &str,
+        safe: &str,
+        ns: &NamespaceSchema,
+    ) -> Result<String> {
+        let guard = format!("SAIKURO_{}_CLIENT_H", safe.to_uppercase());
+
+        let mut lines = vec![
+            format!("#ifndef {guard}"),
+            format!("#define {guard}"),
+            String::new(),
+            "/* AUTO-GENERATED by saikuro-codegen. DO NOT EDIT. */".to_owned(),
+            "#include \"saikuro.h\"".to_owned(),
+            String::new(),
+        ];
+
+        let mut fn_keys: Vec<_> = ns.functions.keys().collect();
+        fn_keys.sort();
+        let mut seen_names: HashMap<String, String> = HashMap::new();
+        for fn_name in fn_keys {
+            let fn_schema = &ns.functions[fn_name];
+            if fn_schema.visibility == Visibility::Private {
+                continue;
+            }
+
+            let c_fn_name = format!("{}_{}", safe, sanitize_ident(fn_name));
+            if let Some(previous_raw) = seen_names.get(&c_fn_name) {
+                return Err(CodegenError::Schema(format!(
+                    "C wrapper name collision in namespace '{ns_name}': '{previous_raw}' and '{fn_name}' both sanitize to '{c_fn_name}'"
+                )));
+            }
+            seen_names.insert(c_fn_name.clone(), fn_name.clone());
+
+            let target = format!("{ns_name}.{fn_name}");
+            let escaped_target = escape_c_string_literal(&target);
+            let ownership_note = "*\n * Returned char* is owned by the caller and must be freed with saikuro_string_free().";
+            if let Some(doc) = &fn_schema.doc {
+                let sanitized_doc = doc.replace("*/", "*\\/");
+                lines.push(format!("/* {sanitized_doc}\n {ownership_note} */"));
+            } else {
+                lines.push(format!("/* {ownership_note} */"));
+            }
+            lines.push(format!(
+                "static inline char* {c_fn_name}(saikuro_client_t client, const char* args_json) {{"
+            ));
+            lines.push(format!(
+                "    return saikuro_client_call_json(client, \"{escaped_target}\", args_json);"
+            ));
+            lines.push("}".to_owned());
+            lines.push(String::new());
+        }
+
+        lines.push("#endif".to_owned());
+        lines.push(String::new());
+
+        Ok(lines.join("\n"))
+    }
+}
+
+fn escape_c_string_literal(s: &str) -> String {
+    let mut out = String::with_capacity(s.len() + 8);
+    for c in s.chars() {
+        match c {
+            '\\' => out.push_str("\\\\"),
+            '"' => out.push_str("\\\""),
+            '\n' => out.push_str("\\n"),
+            '\r' => out.push_str("\\r"),
+            '\t' => out.push_str("\\t"),
+            _ if c.is_control() => {
+                use std::fmt::Write;
+                let _ = write!(out, "\\x{:02X}", c as u32);
+            }
+            _ => out.push(c),
+        }
+    }
+    out
+}
+
+fn sanitize_ident(s: &str) -> String {
+    let mut sanitized: String = s
+        .chars()
+        .map(|c| if c.is_ascii_alphanumeric() { c } else { '_' })
+        .collect();
+    if sanitized
+        .chars()
+        .next()
+        .map(|c| c.is_ascii_digit())
+        .unwrap_or(false)
+    {
+        sanitized.insert(0, '_');
+    }
+    if sanitized.is_empty() {
+        sanitized.push('_');
+    }
+    sanitized
+}
+
+fn normalize_namespace_stem(ns_name: &str) -> String {
+    let mut stem: String = ns_name
+        .replace(['/', '\\', '-'], "_")
+        .chars()
+        .map(|c| if c.is_ascii_alphanumeric() { c } else { '_' })
+        .collect();
+    if stem.is_empty() {
+        stem.push('_');
+    }
+    if stem.chars().next().unwrap().is_ascii_digit() {
+        stem.insert(0, '_');
+    }
+    stem
+}

